const toStr = (v) => String(v ?? '').trim();
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const getEnv = (key) => {
  try {
    if ($env && $env[key]) return String($env[key]).trim();
  } catch (_e) {}
  try {
    const p = (typeof globalThis !== 'undefined' && globalThis.process && globalThis.process.env)
      ? globalThis.process.env[key]
      : '';
    if (p) return String(p).trim();
  } catch (_e) {}
  return '';
};

const deepFindMessage = (obj) => {
  const direct = [
    obj?.chatInput,
    obj?.message,
    obj?.text,
    obj?.input,
    obj?.body?.chatInput,
    obj?.body?.message,
    obj?.body?.text,
    obj?.body?.input,
    obj?.payload?.chatInput,
    obj?.payload?.message,
    obj?.payload?.text,
    obj?.payload?.input,
    obj?.data?.chatInput,
    obj?.data?.message,
    obj?.data?.text,
    obj?.data?.input,
  ];
  for (const c of direct) {
    const s = toStr(c);
    if (s) return s;
  }
  return '';
};

const parseList = (input) =>
  toStr(input)
    .split(/\n|;|\|/g)
    .map((s) => toStr(s).replace(/^[-*\d.)\s]+/, ''))
    .filter(Boolean);

const menuText = [
  'Escolha uma opcao para continuar (envie apenas 1, 2 ou 3):',
  '1) Nova analise de Impacto',
  '2) Duvida sobre funcionalidade ja implementada',
  '3) Correcao de PRs abertas',
  '',
  'Comandos uteis:',
  '/menu: voltar ao menu',
  '/reset: limpar estado da conversa'
].join('\n');

const questions = [
  { field: 'problema', text: 'Qual problema ou oportunidade essa alteracao resolve?' },
  { field: 'mudanca', text: 'Descreva a mudanca como voce espera ver no produto.' },
  { field: 'evidencias', text: 'Quais evidencias/criterios de aceite comprovam que a entrega esta pronta? (lista: uma por linha, ou separadas por ";")' },
  { field: 'restricoes', text: 'Limites de prazo, compliance, integracoes proibidas, etc. (lista: uma por linha, ou separadas por ";")' },
];

const emptyIntake = () => ({
  step: 0,
  problema: '',
  mudanca: '',
  evidencias: [],
  restricoes: [],
  status: '',
  diagnostico: '',
  evidencias_lista: [],
});

const askQuestion = (step) => {
  const idx = Math.max(0, Math.min(Number(step || 0), questions.length - 1));
  return questions[idx].text;
};

const raw = $json || {};
const message = deepFindMessage(raw);
const sessionId = toStr(
  raw.chatId ||
  raw.chat_id ||
  raw.conversationId ||
  raw.conversation_id ||
  raw.metadata?.chatId ||
  raw.metadata?.chat_id ||
  raw.metadata?.conversationId ||
  raw.metadata?.conversation_id ||
  raw.sessionId ||
  raw.session_id ||
  raw.chatSessionId ||
  raw.metadata?.sessionId ||
  'default'
);

const defaultState = {
  mode: '',
  menuShown: false,
  intake: null,
  history: []
};

let state = { ...defaultState };
try {
  const rows = $items('Load Chat State', 0, 0).map((i) => i.json || {});
  const marker = rows.find((r) => toStr(r.complexity_level) === '__chat_state__');
  if (marker && marker.change_summary) {
    const parsed = JSON.parse(String(marker.change_summary));
    if (parsed && typeof parsed === 'object') {
      state = {
        mode: toStr(parsed.mode),
        menuShown: !!parsed.menuShown,
        intake: parsed.intake && typeof parsed.intake === 'object' ? parsed.intake : null,
        history: Array.isArray(parsed.history) ? parsed.history.slice(-20) : []
      };
    }
  }
} catch (_e) {}

const pushHistory = (role, content) => {
  const c = toStr(content);
  if (!c) return;
  state.history.push({ role, content: c });
  if (state.history.length > 20) state.history = state.history.slice(-20);
};

const emit = (payload, nextState) => {
  const s = nextState || state;
  return [{
    json: {
      ...payload,
      session_id: sessionId,
      chat_history: Array.isArray(s.history) ? s.history.slice(-12) : [],
      _chat_state_json: JSON.stringify({
        mode: toStr(s.mode),
        menuShown: !!s.menuShown,
        intake: s.intake && typeof s.intake === 'object' ? s.intake : null,
        history: Array.isArray(s.history) ? s.history.slice(-20) : []
      })
    }
  }];
};

if (!message) {
  state.menuShown = true;
  pushHistory('assistant', menuText);
  return emit({ option: 'invalid', route: 'impact_collect_question', output: menuText }, state);
}

const lower = norm(message);
if (lower === '/reset' || lower === '/menu') {
  state = { ...defaultState, menuShown: true, history: [] };
  pushHistory('assistant', menuText);
  return emit({ option: 'invalid', route: 'impact_collect_question', output: menuText }, state);
}

pushHistory('user', message);

if (state.mode === 'impact_intake') {
  const intake = state.intake && typeof state.intake === 'object' ? state.intake : emptyIntake();
  const idx = Math.max(0, Math.min(Number(intake.step || 0), questions.length - 1));
  const field = questions[idx].field;

  if (field === 'evidencias' || field === 'restricoes') intake[field] = parseList(message);
  else intake[field] = toStr(message);

  intake.step = idx + 1;

  if (intake.step >= questions.length) {
    const evidenciasLista = Array.isArray(intake.evidencias) ? intake.evidencias : [];
    const restricoesLista = Array.isArray(intake.restricoes) ? intake.restricoes : [];
    state.mode = '';
    state.intake = null;

    return emit({
      option: '1',
      route: 'impact_ready',
      ready_for_impact: true,
      problema: toStr(intake.problema),
      mudanca: toStr(intake.mudanca),
      evidencias: evidenciasLista.join('; '),
      restricoes: restricoesLista.join('; '),
      status: toStr(intake.status),
      diagnostico: toStr(intake.diagnostico),
      evidencias_lista: evidenciasLista,
      restricoes_lista: restricoesLista,
    }, state);
  }

  state.intake = intake;
  const output = askQuestion(intake.step);
  pushHistory('assistant', output);
  return emit({ option: '1', route: 'impact_collect_question', output }, state);
}

if (state.mode === 'pr_qa') {
  return emit({
    option: '2',
    route: 'pr_qa',
    question: message,
    owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
    github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
    llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
  }, state);
}

if (state.mode === 'correction_propose') {
  return emit({
    option: '3',
    route: 'correction_propose',
    question: message,
    owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
    github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
    llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
  }, state);
}

const optionMatch = toStr(message).match(/^\s*([123])\s*$/);
if (!optionMatch) {
  state.menuShown = true;
  const output = menuText;
  pushHistory('assistant', output);
  return emit({ option: 'invalid', route: 'impact_collect_question', output }, state);
}

const opt = optionMatch[1];
state.menuShown = true;
if (opt === '1') {
  state.mode = 'impact_intake';
  state.intake = emptyIntake();
  const output = askQuestion(0);
  pushHistory('assistant', output);
  return emit({ option: '1', route: 'impact_collect_question', output }, state);
}

if (opt === '2') {
  state.mode = 'pr_qa';
  const output = 'Opcao 2 selecionada. Agora descreva sua duvida sobre funcionalidade ja implementada.';
  pushHistory('assistant', output);
  return emit({ option: '2', route: 'impact_collect_question', output }, state);
}

state.mode = 'correction_propose';
const output = 'Opcao 3 selecionada. Agora descreva a correcao desejada nas PRs abertas.';
pushHistory('assistant', output);
return emit({ option: '3', route: 'impact_collect_question', output }, state);
